-- Patchnote 0.6.0
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.6.0', 'minor', '2026-04-13T00:00:00.000Z',
  'Plugin ecosystem, homepage builder & PWA',
  'Écosystème de plugins, constructeur d''accueil & PWA',
  '[{"type":"feat","titleEn":"Plugin system v2","titleFr":"Système de plugins v2","descEn":"Complete rewrite of the plugin engine with versioned context factory, event bus, lifecycle hooks, settings validation, plugin logs, and error boundaries","descFr":"Réécriture complète du moteur de plugins avec factory de contexte versionné, bus d''événements, hooks de lifecycle, validation des settings, logs de plugins et error boundaries"},{"type":"feat","titleEn":"Plugin marketplace","titleFr":"Marketplace de plugins","descEn":"Discover community plugins from the admin panel, browse by category, check for updates, one-click server reload","descFr":"Découvrez les plugins communautaires depuis le panneau admin, parcourez par catégorie, vérifiez les mises à jour, rechargement serveur en un clic"},{"type":"feat","titleEn":"Plugin SDK","titleFr":"SDK pour plugins","descEn":"@oscarr/sdk — lightweight helpers for plugin developers: API client, formatters, namespaced storage","descFr":"@oscarr/sdk — helpers légers pour les développeurs de plugins : client API, formateurs, stockage namespacé"},{"type":"feat","titleEn":"Customizable homepage","titleFr":"Page d''accueil personnalisable","descEn":"Admins can reorder, hide/show, and add custom sections to the homepage with a TMDB query builder, endpoint presets (Now Playing, Top Rated...), and live preview","descFr":"Les admins peuvent réordonner, masquer/afficher et ajouter des sections personnalisées à la page d''accueil avec un constructeur de requêtes TMDB, des presets d''endpoints (Au cinéma, Mieux notés...) et un aperçu en direct"},{"type":"feat","titleEn":"PWA support","titleFr":"Support PWA","descEn":"Oscarr is now installable as a Progressive Web App with offline caching for TMDB images and automatic service worker updates","descFr":"Oscarr est désormais installable en tant qu''application web progressive avec cache hors ligne pour les images TMDB et mises à jour automatiques du service worker"},{"type":"feat","titleEn":"Push notifications","titleFr":"Notifications push","descEn":"Get notified on your phone when your requested media becomes available — enable from the user menu, works on Android and desktop","descFr":"Recevez une notification sur votre téléphone quand votre média demandé est disponible — activez depuis le menu utilisateur, fonctionne sur Android et desktop"},{"type":"feat","titleEn":"Request filters","titleFr":"Filtres de demandes","descEn":"Filter requests by status, media type, user and date range on the requests page","descFr":"Filtrez les demandes par statut, type de média, utilisateur et plage de dates sur la page de demandes"},{"type":"feat","titleEn":"Granular frontend RBAC","titleFr":"RBAC frontend granulaire","descEn":"Custom roles (Moderator, Support Manager) now work in the UI — approve, manage tickets, and access admin features based on specific permissions instead of admin-only checks","descFr":"Les rôles personnalisés (Modérateur, Support Manager) fonctionnent maintenant dans l''UI — approuver, gérer les tickets et accéder aux fonctionnalités admin selon les permissions spécifiques"},{"type":"perf","titleEn":"Centralized API hooks","titleFr":"Hooks API centralisés","descEn":"Shared hooks for TMDB data fetching, paginated discovery with infinite scroll, and calendar — eliminates duplicated logic across pages","descFr":"Hooks partagés pour le fetch TMDB, la découverte paginée avec scroll infini et le calendrier — élimine la logique dupliquée entre les pages"},{"type":"refactor","titleEn":"Detail page action button redesign","titleFr":"Refonte du bouton d''action page détail","descEn":"Replaced 90-line nested ternary chain with an explicit state machine — 11 documented states, pure function, fully testable","descFr":"Remplacement de la chaîne ternaire de 90 lignes par une state machine explicite — 11 états documentés, fonction pure, entièrement testable"},{"type":"fix","titleEn":"Upcoming status accuracy","titleFr":"Précision du statut Prochainement","descEn":"Movies already in theaters no longer show as Upcoming — uses earliest known release date instead of digital-first","descFr":"Les films déjà au cinéma ne s''affichent plus comme Prochainement — utilise la date de sortie la plus ancienne connue"},{"type":"fix","titleEn":"Plugin security hardening","titleFr":"Durcissement sécurité plugins","descEn":"Path traversal protection, SSRF prevention, RBAC enforcement, extension whitelist on frontend serving","descFr":"Protection contre le path traversal, prévention SSRF, application RBAC, whitelist d''extensions sur le serving frontend"}]'
);
